				if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						inserted = true
						break
					}
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				fbIdx := dispatch.AssignsLen
				if dispatch.Assigns[fbIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[fbIdx].GenRoute()
					if dispatch.Assigns[fbIdx].Cost >= 0 {
						dispatch.AssignsLen = fbIdx + 1
						inserted = true
					} else {
						dispatch.Assigns[fbIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[fbIdx].GenRoute()
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}
